        >>> game = TwentyFourPointGame()
        >>> nums = [4, 3, 6, 6]
        >>> ans = "4*3+6+6"
        >>> ret = game.evaluate_expression(ans)
        True
        """

        try:
            if eval(expression) == 24:
                return True
            else:
                return False
        except Exception as e:
            return False

